function createConfigurableObject(prefix, useSSL, port, host, onClose, redisHost, redisPort, redisOptions) {
    // Input validation and sanitization
    if (typeof prefix !== 'string') throw new Error('Invalid prefix');
    if (typeof useSSL !== 'boolean') throw new Error('Invalid SSL flag');
    if (typeof port !== 'number' || port < 0) throw new Error('Invalid port');
    if (typeof host !== 'string') throw new Error('Invalid host');
    if (typeof onClose !== 'function') throw new Error('Invalid onClose handler');
    if (typeof redisHost !== 'string') throw new Error('Invalid Redis host');
    if (typeof redisPort !== 'number' || redisPort < 0) throw new Error('Invalid Redis port');
    if (typeof redisOptions !== 'object') throw new Error('Invalid Redis options');

    const config = {
        prefix: prefix || '',
        useSSL: useSSL || false,
        port: port || 80,
        host: host || 'localhost',
        onClose: onClose,
        redis: {
            host: redisHost || 'localhost',
            port: redisPort || 6379,
            options: redisOptions || {}
        }
    };

    config.connect = () => {
        console.log(`Connecting to ${config.host}:${config.port} with SSL set to ${config.useSSL}`);
        // Simulate connection closure
        setTimeout(() => {
            try {
                config.onClose();
            } catch (error) {
                console.error('Error during connection closure:', error);
            }
        }, 1000);
    };

    config.redisConnect = () => {
        console.log(`Connecting to Redis at ${config.redis.host}:${config.redis.port}`);
